#include <bits/stdc++.h>
using namespace std;
long long gcd(long long a,long long b){
    if(b==0)return a;
    return gcd(b,a%b);
}
int main(){
    long long x,y,sum=0;
    cin>>x>>y;
    for(int i=x;i<=y;i+=x){
        long long q=i,p=x*y/i;
        if(x*y%i)continue;
        if(gcd(q,p)==x && q*p/gcd(q,p)==y)sum++;
    }
    cout<<sum;
    return 0;
}
